import React, { useState, useEffect } from 'react';
import { partnerService } from '../../services/api';
import { DollarSign, ShoppingCart, TrendingUp, Award } from 'lucide-react';
import './PartnerDashboard.css';

function PartnerDashboard() {
  const [dashboard, setDashboard] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    loadDashboard();
  }, []);

  const loadDashboard = async () => {
    try {
      setLoading(true);
      const response = await partnerService.getDashboard();
      setDashboard(response.data);
      setError('');
    } catch (err) {
      console.error('Dashboard error:', err);
      setError('Failed to load dashboard');
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    if (!amount && amount !== 0) return '₹0.00';
    return `₹${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-IN', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  if (loading) {
    return <div className="loading">Loading dashboard...</div>;
  }

  if (error) {
    return <div className="error-message">{error}</div>;
  }

  if (!dashboard) {
    return <div className="error-message">No dashboard data available</div>;
  }

  const { stats, recentSales, topProducts } = dashboard;

  return (
    <div className="partner-dashboard">
      <div className="dashboard-header">
        <h1>Partner Dashboard</h1>
        <p className="subtitle">Track your sales performance</p>
      </div>

      {/* Stats Grid */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#fff3e0' }}>
            <ShoppingCart size={24} color="#ff9800" />
          </div>
          <div className="stat-info">
            <h3>Total Sales</h3>
            <p className="stat-value">{stats?.totalSales || 0}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#e3f2fd' }}>
            <DollarSign size={24} color="#2196f3" />
          </div>
          <div className="stat-info">
            <h3>Total Revenue</h3>
            <p className="stat-value">{formatCurrency(stats?.totalRevenue)}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#e8f5e9' }}>
            <TrendingUp size={24} color="#4caf50" />
          </div>
          <div className="stat-info">
            <h3>Total Commission</h3>
            <p className="stat-value">{formatCurrency(stats?.totalCommission)}</p>
          </div>
        </div>

        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#fce4ec' }}>
            <Award size={24} color="#e91e63" />
          </div>
          <div className="stat-info">
            <h3>Paid Commission</h3>
            <p className="stat-value">{formatCurrency(stats?.paidCommission)}</p>
          </div>
        </div>
      </div>

      {/* Top Products */}
      {topProducts && topProducts.length > 0 && (
        <div className="dashboard-section">
          <h2>Top Selling Products</h2>
          <div className="table-container">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Product Name</th>
                  <th>Sales Count</th>
                  <th>Revenue</th>
                  <th>Commission Earned</th>
                </tr>
              </thead>
              <tbody>
                {topProducts.map((product, index) => (
                  <tr key={index}>
                    <td className="product-name">{product.productName}</td>
                    <td>{product.salesCount}</td>
                    <td className="amount">{formatCurrency(product.totalRevenue)}</td>
                    <td className="amount">{formatCurrency(product.totalCommission)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Recent Sales */}
      {recentSales && recentSales.length > 0 && (
        <div className="dashboard-section">
          <h2>Recent Sales</h2>
          <div className="table-container">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Product</th>
                  <th>Buyer</th>
                  <th>Amount</th>
                  <th>Commission</th>
                  <th>Status</th>
                  <th>License Key</th>
                </tr>
              </thead>
              <tbody>
                {recentSales.map((sale) => (
                  <tr key={sale.saleId}>
                    <td>{formatDate(sale.saleDate)}</td>
                    <td className="product-name">{sale.productName}</td>
                    <td>
                      <div>
                        <div className="buyer-name">{sale.buyerName}</div>
                        <div className="buyer-email">{sale.buyerEmail}</div>
                      </div>
                    </td>
                    <td className="amount">{formatCurrency(sale.saleAmount)}</td>
                    <td className="amount">{formatCurrency(sale.commissionAmount)}</td>
                    <td>
                      <span className={`status-badge status-${sale.paymentStatus.toLowerCase()}`}>
                        {sale.paymentStatus}
                      </span>
                    </td>
                    <td className="license-key">{sale.licenseKey}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Empty State */}
      {(!recentSales || recentSales.length === 0) && (
        <div className="empty-state">
          <ShoppingCart size={64} color="#ccc" />
          <h3>No Sales Yet</h3>
          <p>Start selling products to see your performance metrics!</p>
        </div>
      )}
    </div>
  );
}

export default PartnerDashboard;
